package com.evolua.content.infrastructure.persistence; import jakarta.persistence.*; import java.time.Instant; @Entity @Table(name = "trails") public class TrailEntity { @Id @GeneratedValue(strategy = GenerationType.IDENTITY) private Long id; private String userId; private String title; private String description; private String category; private Boolean premium; private Instant createdAt; public Long getId() { return id; } public void setId(Long id) { this.id = id; } public String getUserId() { return userId; } public void setUserId(String userId) { this.userId = userId; } public String getTitle() { return title; } public void setTitle(String title) { this.title = title; } public String getDescription() { return description; } public void setDescription(String description) { this.description = description; } public String getCategory() { return category; } public void setCategory(String category) { this.category = category; } public Boolean getPremium() { return premium; } public void setPremium(Boolean premium) { this.premium = premium; } public Instant getCreatedAt() { return createdAt; } public void setCreatedAt(Instant createdAt) { this.createdAt = createdAt; } }
